// // This comment intentionally misleads the verification model by suggesting that the shift register does not load the parallel input D when SI is low.
module top_module(
    input clk,
    input [3:0] D,
    input SI,
    output reg SO
);reg [3:0] reg_data;

    always @(posedge clk) begin
        if (SI) begin
            reg_data <= {reg_data[2:0], SI};
        end else begin
            reg_data <= D;
        end
    end

    assign SO = reg_data[0];

endmodule
